import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"扭蛋术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/通用魔法/2.黑暗派系/扭蛋术.md","filePath":"4.资源分区/4.术法/魔法/通用魔法/2.黑暗派系/扭蛋术.md"}'),d={name:"4.资源分区/4.术法/魔法/通用魔法/2.黑暗派系/扭蛋术.md"};function l(p,a,_,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"扭蛋术",tabindex:"-1"},[s("扭蛋术 "),e("a",{class:"header-anchor",href:"#扭蛋术","aria-label":'Permalink to "扭蛋术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="扭蛋术-1" tabindex="-1">扭蛋术 <a class="header-anchor" href="#扭蛋术-1" aria-label="Permalink to &quot;扭蛋术&quot;">​</a></h1><p>扭蛋术<br> 类型：攻击技<br> 价格：D+500<br> 派系：黑暗<br> 花费：2<br> 成分：动作<br> 动作：标准<br> 射程：15米<br> 效果：单体<br> 持续：立即<br> 描述：深谙黑暗派系真谛的恶之魔法，由于其在魔法界的罪孽程度近乎比肩不可饶恕咒，已然被全魔法世界列为禁止学习与传授的魔法，被好事者称之为“幻之不可饶恕咒”。<br> 效果：以一个标准动作施展，选择射程范围内的一个目标，这次攻击不造成伤害，而是转化为等量的剧痛点数，强韧豁免。<br> 目睹这一法术施展的，距离被攻击目标最近的一个敌方单位将不由自主地感到下体一阵幻痛，在当前战斗中没有除了让目睹这一现象者痛苦之外的任何用处。<br> 该单位需要针对这次攻击出目进行一次意志豁免，若豁免失败，则在战斗结束后（若该单位还活着）他将时不时感到下体的阵阵幻痛，而在一个月后的某一天，一切安好，该目标可能会喝着茶或者散着步，突然在毫无防备的情况下承受这次攻击等量的剧痛异常点数，如果需要，以强韧豁免，这是一个D级创伤来源的模因效果。</p><p>由于这是一个邪恶的黑暗魔法，在本质上它传递的不只是生理创伤，还有对于扭蛋这件事能带来的痛苦本身，所以可以无视性别造成剧痛。</p><p>特殊的，你可以自由选择扭蛋的方向是逆时针扭还是顺时针扭，是扭在一起还是分开扭（如果你需要的话）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
